/* ===== NovaFlow interaction pass ===== */
(function(){
  const i18n={
    EN:{Workspace:'Workspace',Intelligence:'Intelligence',Account:'Account',Journal:'Journal',Analytics:'Analytics',Progress:'Progress',Digest:'Digest',Premarket:'Premarket',Settings:'Settings','Trade Screenshot':'Attachment','Run Trade Audit':'Trade Audit','Add Trade':'Add Trade'},
    RU:{Workspace:'Разделы',Intelligence:'Интеллект',Account:'Аккаунт',Journal:'Журнал',Analytics:'Аналитика',Progress:'Прогресс',Digest:'Дайджест',Premarket:'Премаркет',Settings:'Настройки','Trade Screenshot':'Вложение','Run Trade Audit':'Аудит сделки','Add Trade':'Добавить сделку'}
  };
  function syncLangToggle(){
    const t=document.getElementById('lang-toggle');
    if(t) t.checked = (_currentLang==='RU');
  }
  function applyLangUI(){
    syncLangToggle();
    document.querySelectorAll('.apple-menu-trigger').forEach(el=>{
      const key=el.childNodes[0]&&el.childNodes[0].nodeType===3?el.childNodes[0].textContent.trim():'';
      if(i18n[_currentLang][key]) el.childNodes[0].textContent=i18n[_currentLang][key]+' ';
    });
    const page=document.getElementById('apple-current-page');
    if(page && i18n[_currentLang][page.textContent.trim()]) page.textContent=i18n[_currentLang][page.textContent.trim()];
    document.querySelectorAll('label').forEach(el=>{const txt=el.textContent.trim(); if(i18n[_currentLang][txt]) el.textContent=i18n[_currentLang][txt];});
    document.querySelectorAll('button').forEach(el=>{const txt=el.textContent.trim(); if(i18n[_currentLang][txt]) el.textContent=i18n[_currentLang][txt];});
  }
  const oldToggleLang=window.toggleLang;
  window.toggleLang=function(){
    _currentLang = _currentLang==='RU' ? 'EN' : 'RU';
    localStorage.setItem('orb_lang',_currentLang);
    applyLangUI();
    if(typeof oldToggleLang==='function') try{oldToggleLang()}catch(e){}
  };
  window.openBrutalModal=function(){
    var modal=document.getElementById('brutal-modal')||document.getElementById('ai-modal');
    if(modal) modal.classList.add('open');
    else if(typeof runBrutalAnalysis==='function') runBrutalAnalysis();
  };
  function setupAppleMenus(){
    const menus=[...document.querySelectorAll('.apple-menu')];
    let closeTimer=null;
    function closeAll(){menus.forEach(m=>m.classList.remove('open'));}
    window.closeAppleMenus=closeAll;
    menus.forEach(menu=>{
      menu.addEventListener('mouseenter',()=>{clearTimeout(closeTimer); closeAll(); menu.classList.add('open');});
      menu.addEventListener('mouseleave',()=>{closeTimer=setTimeout(()=>menu.classList.remove('open'),120);});
      const btn=menu.querySelector('.apple-menu-trigger');
      if(btn) btn.addEventListener('click',(e)=>{e.preventDefault(); const open=menu.classList.contains('open'); closeAll(); if(!open) menu.classList.add('open');});
    });
    document.addEventListener('click',(e)=>{if(!e.target.closest('.apple-menu')) closeAll();});
  }
  function setupSpotlight(){
    document.querySelectorAll('.stat-cell,.dash-card,.fcard,.tcard,.coach-card,.settings-card,.pm-section-card,.mc-card,.hm-card').forEach(card=>{
      card.addEventListener('mousemove',e=>{const r=card.getBoundingClientRect(); card.style.setProperty('--spot-x', (e.clientX-r.left)+'px'); card.style.setProperty('--spot-y', (e.clientY-r.top)+'px');});
    });
  }
  document.addEventListener('DOMContentLoaded',()=>{syncLangToggle(); applyLangUI(); setupAppleMenus(); setupSpotlight();});
})();
